function nextTabWithValidate(e){const t=e.target.closest(".tab-pane"),a=document.querySelector(e.target.dataset.nextTabWithValidate),n=document.querySelector(`.nav-link[href="#${a.id}"]`);if(validateInputs(t)&&a){new bootstrap.Tab(n).show(),n.classList.remove("disabled")}}function validateInputs(e){const t=e.querySelectorAll("input, select, textarea");let a=!0;return t.forEach((e=>{e.checkValidity()?e.classList.remove("is-invalid"):(a=!1,e.classList.add("is-invalid"))})),a}function previousTab(e){const t=document.querySelector(e.target.dataset.previousTab),a=document.querySelector(`.nav-link[href="#${t.id}"]`);new bootstrap.Tab(a).show()}function nextTab(e){const t=document.querySelector(e.target.dataset.nextTab),a=document.querySelector(`.nav-link[href="#${t.id}"]`);new bootstrap.Tab(a).show()}function resetTabs(e){e.querySelectorAll(".nav-link").forEach((e=>e.classList.add("disabled")));const t=e.querySelector(".main-tab");t.classList.remove("disabled");new bootstrap.Tab(t).show()}document.querySelectorAll("[data-next-tab-with-validate]").forEach((function(e){e.addEventListener("click",nextTabWithValidate)})),document.querySelectorAll("[data-previous-tab]").forEach((function(e){e.addEventListener("click",previousTab)})),document.querySelectorAll("[data-next-tab]").forEach((function(e){e.addEventListener("click",nextTab)}));